import{_ as i,C as n,o as t,c,j as r,a,b as p,w as s,E as l,a6 as d,a5 as h}from"./chunks/framework.C86FyxWD.js";const w=JSON.parse('{"title":"API sharing","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/api-sharing.md","filePath":"concepts/api-sharing.md"}'),m={name:"concepts/api-sharing.md"};function u(f,e,k,P,v,b){const o=n("Mermaid");return t(),c("div",null,[e[1]||(e[1]=r("h1",{id:"api-sharing",tabindex:"-1"},[a("API sharing "),r("a",{class:"header-anchor",href:"#api-sharing","aria-label":'Permalink to "API sharing"'},"​")],-1)),e[2]||(e[2]=r("p",null,"Platform Mesh uses kcp API sharing primitives to connect service providers and service consumers without giving consumers direct access to provider runtimes.",-1)),e[3]||(e[3]=r("p",null,"This page explains how Platform Mesh uses those primitives. kcp owns the canonical behavior and field-level semantics.",-1)),e[4]||(e[4]=r("h2",{id:"provider-and-consumer-boundary",tabindex:"-1"},[a("Provider and consumer boundary "),r("a",{class:"header-anchor",href:"#provider-and-consumer-boundary","aria-label":'Permalink to "Provider and consumer boundary"'},"​")],-1)),e[5]||(e[5]=r("p",null,"A service provider publishes a service API from a provider workspace. A service consumer makes that API available in a consumer workspace and creates desired-state resources there.",-1)),(t(),p(d,null,{default:s(()=>[l(o,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Provider%5B%22Provider%20workspace%22%5D%0A%20%20%20%20Export%5B%22APIExport%22%5D%0A%20%20%20%20Consumer%5B%22Consumer%20workspace%22%5D%0A%20%20%20%20Binding%5B%22APIBinding%22%5D%0A%0A%20%20%20%20Provider%20--%3E%20Export%0A%20%20%20%20Consumer%20--%3E%20Binding%0A%20%20%20%20Binding%20--%20%22binds%20to%22%20--%3E%20Export%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[a(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=h('<p>The provider owns the API contract and service automation. The consumer owns the requested service resources in its account workspace. Platform Mesh mediates the relationship through workspaces, identity, authorization, and declarative APIs.</p><h2 id="kcp-primitives-used-by-platform-mesh" tabindex="-1">kcp primitives used by Platform Mesh <a class="header-anchor" href="#kcp-primitives-used-by-platform-mesh" aria-label="Permalink to &quot;kcp primitives used by Platform Mesh&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Primitive</th><th>Platform Mesh role</th></tr></thead><tbody><tr><td>APIExport</td><td>Provider-side contract for a service API.</td></tr><tr><td>APIBinding</td><td>Consumer-side binding that makes a provider API available in a consumer workspace.</td></tr><tr><td>APIResourceSchema</td><td>Schema object behind exported kcp APIs.</td></tr><tr><td>Permission claim</td><td>Provider request for bounded access to related consumer-side resources, such as Secrets or ConfigMaps.</td></tr><tr><td>Virtual workspace</td><td>Wildcard endpoint per APIExport that providers watch to see consumer-bound objects without per-workspace credentials.</td></tr><tr><td>Identity hash</td><td>Stable tag in <code>APIExport.status.identityHash</code> providers use to scope wildcard reads when multiple providers export the same group/resource.</td></tr></tbody></table><h2 id="platform-mesh-usage" tabindex="-1">Platform Mesh usage <a class="header-anchor" href="#platform-mesh-usage" aria-label="Permalink to &quot;Platform Mesh usage&quot;">​</a></h2><ul><li>api-syncagent can publish CRD-based provider services through APIExports.</li><li>multicluster-runtime can be used by provider controllers that watch resources across workspaces.</li><li>Marketplace and portal workflows can guide or create APIBindings for consumers.</li><li>Permission claims are part of the provider-consumer trust boundary and should be accepted intentionally.</li></ul><h2 id="permission-claims" tabindex="-1">Permission claims <a class="header-anchor" href="#permission-claims" aria-label="Permalink to &quot;Permission claims&quot;">​</a></h2><p>A provider often needs bounded access to a few resources outside its own API — to write a <code>Secret</code> with connection credentials, read a credential the consumer placed in the workspace, or emit <code>events</code>. Permission claims are the consent mechanic for that access: the provider declares what it needs on the APIExport; the consumer accepts each claim explicitly on the APIBinding. Neither side can unilaterally escalate.</p><p>Claims can be scoped by verb (read-only versus full access) and, in principle, by object selector. Platform Mesh itself is bootstrapped through this mechanism — the <code>core.platform-mesh.io</code> APIExport in <code>platform-mesh-system</code> claims access to workspaces, apibindings, logical clusters, and secrets so the account-operator can reconcile them on every account&#39;s behalf.</p><p>For the full Platform Mesh examples, see <a href="/pr-preview/pr-229/reference/components/kcp/api-sharing.html">API sharing reference</a>. For field-level semantics, see <a href="https://docs.kcp.io/kcp/main/concepts/apis/exporting-apis/#permission-claims" target="_blank" rel="noreferrer">permission claims</a> in the kcp docs.</p><h2 id="virtual-workspaces" tabindex="-1">Virtual workspaces <a class="header-anchor" href="#virtual-workspaces" aria-label="Permalink to &quot;Virtual workspaces&quot;">​</a></h2><p>A provider with many consumer bindings cannot watch each consumer workspace separately. kcp solves this by publishing <em>virtual workspace</em> endpoints — wildcard views that aggregate all bound objects across consumers on one kcp shard. Provider controllers connect to that one endpoint, see every relevant object annotated with its source workspace, and write status back through the same path.</p><p>Every Platform Mesh operator (account-operator, security-operator, rebac-authz-webhook, the GraphQL gateway, marketplace, and per-service operators) consumes virtual workspaces this way. Controllers do not construct URLs by hand; they read them from <code>APIExportEndpointSlice.status</code>.</p><p>For URL contracts, terminating-phase endpoints, and Go discovery snippets, see <a href="/pr-preview/pr-229/reference/components/kcp/virtual-workspaces.html">Virtual workspaces reference</a>.</p><h2 id="how-platform-mesh-layers-on-this" tabindex="-1">How Platform Mesh layers on this <a class="header-anchor" href="#how-platform-mesh-layers-on-this" aria-label="Permalink to &quot;How Platform Mesh layers on this&quot;">​</a></h2><p>The kcp primitives are generic. Platform Mesh layers account structure and lifecycle wiring on top:</p><ul><li><strong>Where APIExports live.</strong> Platform Mesh provisions dedicated provider workspaces under a known path. The platform owner controls those locations; providers do not pick arbitrary paths.</li><li><strong>Who consumes.</strong> Consumer workspaces are mapped to <a href="./account-model.html">Accounts</a> in the Platform Mesh hierarchy. APIBindings live inside a consumer Account&#39;s workspace.</li><li><strong>Authorization wiring.</strong> When a binding is activated, Platform Mesh updates the consumer Account&#39;s <a href="./identity-and-authorization.html">IAM store</a> so the new API surfaces are covered by OpenFGA alongside the rest of the workspace.</li></ul><p>A bare APIExport without Platform Mesh wiring works fine in vanilla kcp but does not appear in the marketplace, does not participate in IAM enforcement, and is not discoverable through the Platform Mesh Portal.</p><h2 id="upstream-kcp-ownership" tabindex="-1">Upstream kcp ownership <a class="header-anchor" href="#upstream-kcp-ownership" aria-label="Permalink to &quot;Upstream kcp ownership&quot;">​</a></h2><p>kcp owns APIExport, APIBinding, APIResourceSchema, permission claim, identity, and virtual workspace semantics.</p><p>Reference upstream kcp documentation for canonical behavior:</p><ul><li><a href="https://docs.kcp.io/kcp/main/concepts/apis/exporting-apis/" target="_blank" rel="noreferrer">Exporting and binding APIs</a></li><li><a href="https://docs.kcp.io/kcp/main/reference/crd/apis.kcp.io/apibindings/" target="_blank" rel="noreferrer">APIBinding CRD reference</a></li><li><a href="https://docs.kcp.io/kcp/main/reference/crd/apis.kcp.io/apiexports/" target="_blank" rel="noreferrer">APIExport CRD reference</a></li><li><a href="https://docs.kcp.io/kcp/main/reference/crd/apis.kcp.io/apiresourceschemas/" target="_blank" rel="noreferrer">APIResourceSchema CRD reference</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-229/reference/components/kcp/api-sharing.html">API sharing in kcp</a> — primitives reference</li><li><a href="./control-planes.html">Control planes</a></li><li><a href="./integration-paths.html">Integration paths</a></li><li><a href="./interaction-patterns/provider-to-consumer.html">Provider to consumer</a></li></ul>',23))])}const A=i(m,[["render",u]]);export{w as __pageData,A as default};
